// ============================================================
// Normaliza e valida o payload recebido do EA MT5
// Mapeia para o schema real do Supabase (tabelas options / price_history)
// ============================================================

const item = $input.first().json.body;

// Validação básica
if (!item.simbolo || !item.tipo || item.preco === undefined) {
  throw new Error(`Payload inválido: ${JSON.stringify(item)}`);
}

const tipo = (item.tipo || '').toUpperCase();
if (!['CALL', 'PUT'].includes(tipo)) {
  throw new Error(`Tipo de opção inválido: ${item.tipo}`);
}

// timestamp MT5 "2024.06.15 14:30:00" -> "2024-06-15 14:30:00" (aceito pelo Postgres)
const tsRaw = item.timestamp || new Date().toISOString();
const tsISO = tsRaw.replace(/^(\d{4})\.(\d{2})\.(\d{2})/, '$1-$2-$3');

// vencimento MT5 "2024.06.15" -> "2024-06-15" (coluna date)
let expiration_date = null;
if (item.vencimento) {
  const candidato = item.vencimento.replace(/\./g, '-');
  if (/^\d{4}-\d{2}-\d{2}$/.test(candidato)) expiration_date = candidato;
}

// Extrai strike do nome do símbolo se não vier (ex: PETR4C350 -> 350)
let strike = parseFloat(item.strike) || 0;
if (!strike) {
  const match = item.simbolo.match(/[CP](\d+)$/i);
  if (match) strike = parseFloat(match[1]);
}

const bid = parseFloat(item.bid) || 0;
const ask = parseFloat(item.ask) || 0;

// Opção é considerada ativa se ainda não venceu (ou se não há data conhecida)
let is_active = true;
if (expiration_date) {
  const hoje = new Date().toISOString().slice(0, 10);
  is_active = expiration_date >= hoje;
}

return [{
  json: {
    ticker:             item.simbolo.toUpperCase(),
    ticker_main:        item.ativo_base.toUpperCase(),
    option_type:        tipo,
    strike_price:       strike,
    expiration_date:    expiration_date,
    is_active:          is_active,
    price:              parseFloat(item.preco) || 0,
    bid:                bid,
    ask:                ask,
    spread:             (bid > 0 && ask > 0) ? +(ask - bid).toFixed(4) : 0,
    collected_at:       tsISO,
    is_historical_load: item.carga_historica === true || item.carga_historica === 'true'
  }
}];

// Mescla dados normalizados com o id retornado pelo upsert
const normalizado = $('Normalizar Payload').first().json;
const upsertResult = $input.first().json;

if (!upsertResult || upsertResult.id === undefined) {
  throw new Error(`Upsert não retornou id da opção: ${JSON.stringify(upsertResult)}`);
}

return [{
  json: {
    ...normalizado,
    option_id: upsertResult.id
  }
}];
